={{
(() => {
  const logradouro = $json["logradouro"] || "";
  const numero = $json["numero"] || "";
  const complemento = $json["complemento"] ? " - " + $json["complemento"] : "";
  const bairro = $json["bairro"] || "";
  const municipio = $json["municipio"] || "";
  const uf = ($json["uf"] || "").toUpperCase();
  const cep = ($json["cep"] || "").replace(/\D/g, "").replace(/(\d{5})(\d{3})/, "$1-$2");

  // Função para colocar a primeira letra de cada palavra em maiúscula
  const titleCase = (str) =>
    str
      .toLowerCase()
      .replace(/\b[a-zà-ú]/gi, (c) => c.toUpperCase());

  return `${titleCase(logradouro)}, ${numero}${complemento}, ${titleCase(bairro)}, ${titleCase(municipio)}, ${uf}, ${cep}`;
})()
}}

fieldValues.fieldValue:
={{
  (() => {
    const raw = $('Set Campos').item.json.data_inicio_prazo;
    if (!raw) return null;

    // separa por / ou - automaticamente
    const parts = raw.includes('/') ? raw.split('/') : raw.split('-');

    // garante que sejam 3 partes (dia, mês, ano)
    if (parts.length !== 3) return null;

    // detecta se o formato é dd/mm/yyyy ou yyyy-mm-dd
    const isYearFirst = parts[0].length === 4;

    // monta o ISO (yyyy-mm-dd)
    const [day, month, year] = isYearFirst
      ? [parts[2], parts[1], parts[0]]
      : [parts[0], parts[1], parts[2]];

    // valida os números
    if (
      isNaN(Number(day)) ||
      isNaN(Number(month)) ||
      isNaN(Number(year))
    ) return null;

    return `${year.padStart(4, '0')}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
  })()
}}

value.VALOR CRÉDITO:
={{
  (() => {
    const raw = $('Set Campos').item.json.valor_credito;
    if (!raw) return 'R$ 0,00';

    // remove tudo que não é número ou ponto/vírgula
    let numStr = raw.toString().replace(/[^\d.,]/g, '');

    // substitui vírgulas por pontos se houver só uma vírgula decimal
    if (numStr.includes(',') && numStr.split(',').length === 2 && !numStr.includes('.')) {
      numStr = numStr.replace(',', '.');
    } else {
      // remove pontos de milhar e troca vírgula decimal por ponto
      numStr = numStr.replace(/\./g, '').replace(',', '.');
    }

    const value = parseFloat(numStr);
    if (isNaN(value)) return 'R$ 0,00';

    // formata no padrão BRL
    return value.toLocaleString('pt-BR', {
      style: 'currency',
      currency: 'BRL',
      minimumFractionDigits: 2,
    });
  })()
}}

